import { useState } from "react";
import {
  Box,
  Card,
  CardContent,
  Typography,
  TextField,
  Button,
  Grid,
} from "@mui/material";
import API from "../../api/axios";

export default function ProjectSetup() {
  const [form, setForm] = useState({
    username: "",
    password: "",
    confirmPassword: "",
    projectName: "",
    description: "",
    startDate: "",
    endDate: "",
  });

  const [loading, setLoading] = useState(false);

  // 🔹 COMMON CHANGE HANDLER
  const handleChange = (field) => (e) => {
    setForm({ ...form, [field]: e.target.value });
  };

  // 🚀 SUBMIT (USER + PROJECT)
  const handleSubmit = async () => {
    if (loading) return;

    // 🔥 validation
    if (form.password !== form.confirmPassword) {
      alert("Passwords do not match ❌");
      return;
    }

    if (!form.username || !form.password || !form.projectName) {
      alert("Fill required fields ❌");
      return;
    }

    try {
      setLoading(true);

      await API.post(
        "create-project-user/",
        {
          username: form.username,
          password: form.password,
          project_name: form.projectName,
          description: form.description,
          start_date: form.startDate,
          end_date: form.endDate,
        },
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        },
      );

      alert("Project + User Created Successfully ✅");

      // 🔄 reset
      setForm({
        username: "",
        password: "",
        confirmPassword: "",
        projectName: "",
        description: "",
        startDate: "",
        endDate: "",
      });
    } catch (err) {
      const errorMessage =
        err.response?.data?.message ||
        err.response?.data?.detail ||
        "Something went wrong ❌";

      alert(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      sx={{
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        background: "linear-gradient(135deg, #e3f2fd, #ffffff)",
        p: 2,
      }}
    >
      <Grid container spacing={3} maxWidth={900}>
        {/* 🔥 LEFT - CREATE USER */}
        <Grid item xs={12} md={6}>
          <Card sx={{ p: 3, borderRadius: 4 }}>
            <CardContent>
              <Typography variant="h6" mb={2} fontWeight="bold">
                Create User
              </Typography>

              <TextField
                fullWidth
                label="Username"
                margin="normal"
                value={form.username}
                onChange={handleChange("username")}
              />

              <TextField
                fullWidth
                label="Password"
                type="password"
                margin="normal"
                value={form.password}
                onChange={handleChange("password")}
              />

              <TextField
                fullWidth
                label="Confirm Password"
                type="password"
                margin="normal"
                value={form.confirmPassword}
                onChange={handleChange("confirmPassword")}
              />
            </CardContent>
          </Card>
        </Grid>

        {/* 🔥 RIGHT - CREATE PROJECT */}
        <Grid item xs={12} md={6}>
          <Card sx={{ p: 3, borderRadius: 4 }}>
            <CardContent>
              <Typography variant="h6" mb={2} fontWeight="bold">
                Create Project
              </Typography>

              <TextField
                fullWidth
                label="Project Name"
                margin="normal"
                value={form.projectName}
                onChange={handleChange("projectName")}
              />

              <TextField
                fullWidth
                label="Description"
                margin="normal"
                value={form.description}
                onChange={handleChange("description")}
              />

              <TextField
                fullWidth
                label="Start Date"
                type="date"
                margin="normal"
                InputLabelProps={{ shrink: true }}
                value={form.startDate}
                onChange={handleChange("startDate")}
              />

              <TextField
                fullWidth
                label="End Date"
                type="date"
                margin="normal"
                InputLabelProps={{ shrink: true }}
                value={form.endDate}
                onChange={handleChange("endDate")}
              />
            </CardContent>
          </Card>
        </Grid>

        {/* 🔥 BUTTON (CENTER FULL WIDTH) */}
        <Grid item xs={12}>
          <Button
            fullWidth
            variant="contained"
            sx={{
              mt: 1,
              borderRadius: 5,
              py: 1.5,
              fontWeight: "bold",
              fontSize: 16,
            }}
            onClick={handleSubmit}
            disabled={loading}
          >
            {loading ? "Creating..." : "CREATE USER & PROJECT"}
          </Button>
        </Grid>
      </Grid>
    </Box>
  );
}
